# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3, HTTPProvider
from eth_account.messages import encode_defunct

app = Flask(__name__)

# Initialize web3
w3 = Web3(HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'))

@app.route('/verify-signature', methods=['POST'])
def verify_signature():
    try:
        data = request.get_json()
        message = data.get('message')
        signature = data.get('signature')
        expected_address = data.get('address')

        # Create message object
        message_encoded = encode_defunct(text=message)

        # Recover address from the signed message
        recovered_address = w3.eth.account.recover_message(message_encoded, signature=signature)

        # Check if recovered address matches the expected address
        if recovered_address.lower() == expected_address.lower():
            return jsonify({'authenticated': True, 'address': recovered_address}), 200
        else:
            return jsonify({'authenticated': False, 'error': 'Address mismatch'}), 401

    except Exception as e:
        return jsonify({'authenticated': False, 'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=True)